class Solution {
public:
    vector<int> waysToFillArray(vector<int>& nums, int k, vector<vector<int>>& queries) {
        vector<int> result;
        for (auto& query : queries) {
            int index = query[0], value = query[1], start = query[2], x = query[3];
            nums[index] = value;
            int count = 0;
